challenges.solution:
in vec2 v_uv;
out vec4 fragColor;

void main() {
    // Simulate a 64x64 compute dispatch grid using UV coordinates
    float threadX = floor(v_uv.x * 64.0);
    float threadY = floor(v_uv.y * 64.0);

    // Color first half of columns red, second half blue
    vec3 col = threadX < 32.0 ? vec3(0.8, 0.2, 0.1) : vec3(0.1, 0.3, 0.8);

    // Bright stripe every 8 threads to show workgroup boundaries
    if (mod(threadX, 8.0) < 1.0 || mod(threadY, 8.0) < 1.0) {
        col = vec3(1.0);
    }

    fragColor = vec4(col, 1.0);
}

hlsl.code:
float4 main(float2 uv : TEXCOORD0) : SV_Target {
    float threadX = floor(uv.x * 64.0);
    float threadY = floor(uv.y * 64.0);
    float3 col = threadX < 32.0 ? float3(0.8, 0.2, 0.1) : float3(0.1, 0.3, 0.8);
    if (fmod(threadX, 8.0) < 1.0 || fmod(threadY, 8.0) < 1.0) {
        col = float3(1.0, 1.0, 1.0);
    }
    return float4(col, 1.0);
}

